SELECT SUM(trans_perf_cnt) AS trans_perf_cnt, SUM(trans_alarm_cnt) AS trans_alarm_cnt, SUM(ip_resource_cnt) AS ip_resource_cnt, SUM(ip_alarm_cnt) AS ip_alarm_cnt, SUM(ip_perf_cnt) AS ip_perf_cnt, SUM(ip_sflow_cnt) AS ip_sflow_cnt, SUM(ticket_rt_cnt) AS ticket_rt_cnt, SUM(ticket_att_cnt) AS ticket_att_cnt, SUM(ticket_ntt_cnt) AS ticket_ntt_cnt, SUM(ticket_pf_cnt) AS ticket_pf_cnt, SUM(link_total_resource_cnt) AS link_total_resource_cnt, SUM(link_total_alarm_cnt) AS link_total_alarm_cnt, SUM(link_ip_perf_cnt) AS link_ip_perf_cnt, SUM(link_trans_perf_cnt) AS link_trans_perf_cnt FROM nia.tb_opsts WHERE 1=1
AND opsts_time = #{SEARCH_DATE}
AND opsts_gb = #{DATE_TYPE}
